/**
 * API Service
 * Clean Axios instance with safe auth handling
 */

import axios from 'axios';
import toast from 'react-hot-toast';

const API_URL =
  process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

// Create axios instance
const api = axios.create({
  baseURL: API_URL,
  headers: { 'Content-Type': 'application/json' },
  timeout: 15000,
});

// ============================================================
// Prevent multiple logout + toast spam
// ============================================================
let isLoggingOut = false;

// ============================================================
// Request Interceptor - Attach JWT token
// ============================================================
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('taskflow_token');

    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }

    return config;
  },
  (error) => Promise.reject(error)
);

// ============================================================
// Response Interceptor - Safe global error handling
// ============================================================
api.interceptors.response.use(
  (response) => response,
  (error) => {
    const status = error.response?.status;
    const message =
      error.response?.data?.message || 'Something went wrong';

    // ========================================================
    // Handle 401 (Unauthorized) ONLY ONCE
    // ========================================================
    if (status === 401 && !isLoggingOut) {
      const url = error.config?.url || '';

      const isAuthRoute =
        url.includes('/auth/login') ||
        url.includes('/auth/register');

      if (!isAuthRoute) {
        isLoggingOut = true;

        // Clear storage
        localStorage.removeItem('taskflow_token');
        localStorage.removeItem('taskflow_user');

        // Show only ONE toast
        toast.error('Session expired. Please log in again.');

        // Let UI settle before redirect (prevents loop spam)
        setTimeout(() => {
          window.location.href = '/login';
        }, 300);
      }
    }

    return Promise.reject({
      message,
      status,
    });
  }
);

// ============================================================
// Auth API
// ============================================================
export const authAPI = {
  register: (data) => api.post('/auth/register', data),
  login: (data) => api.post('/auth/login', data),
  getMe: () => api.get('/auth/me'),
  updateProfile: (data) => api.put('/auth/profile', data),
  changePassword: (data) => api.put('/auth/change-password', data),
};

// ============================================================
// Tasks API
// ============================================================
export const tasksAPI = {
  getAll: (params) => api.get('/tasks', { params }),
  getOne: (id) => api.get(`/tasks/${id}`),
  create: (data) => api.post('/tasks', data),
  update: (id, data) => api.put(`/tasks/${id}`, data),
  delete: (id) => api.delete(`/tasks/${id}`),
  getStats: () => api.get('/tasks/stats'),
  bulkUpdate: (data) => api.patch('/tasks/bulk-update', data),
};

export default api;
